static void test_backend_init_creates_handle(void) {
    printf("\n--- test_backend_init_creates_handle ---\n");
    cuda_backend_init();

    cublasHandle_t handle = cuda_backend_get_handle();
    ASSERT_NOT_NULL(handle, "handle is non-NULL after init");
}

static void test_backend_cleanup_nulls_handle(void) {
    printf("\n--- test_backend_cleanup_nulls_handle ---\n");
    cuda_backend_cleanup();

    cublasHandle_t handle = cuda_backend_get_handle();
    ASSERT_NULL(handle, "handle is NULL after cleanup");

    cuda_backend_init();
}

